body:
Found on verilator master branch

A string literal in a function argument is incorrectly converted to `unsigned long long` instead of `std::string`

I needed to put the function in a package and a class, I think to avoid optimazations that hid this problem.

The following verilog code:

`file: tjo_p.sv`
```systemverilog
package tjo_p;
    class Tjo;
        function automatic string broken_str_arg(input string some_string);
            $display(some_string);
            return some_string;
        endfunction
    endclass
endpackage
```
`file: tjo.sv`
```systemverilog
module tjo();

initial begin
    tjo_p::Tjo tc;
    string bar = "baar";
    $display(tc.broken_str_arg("foo"));
    $display(tc.broken_str_arg(bar));
end
endmodule
```

Gets converted into this cpp code:
```cpp
VL_ATTR_COLD void Vtjo___024root___initial__TOP__0(Vtjo___024root* vlSelf) {
    if (false && vlSelf) {}  // Prevent unused
    Vtjo__Syms* const __restrict vlSymsp VL_ATTR_UNUSED = vlSelf->vlSymsp;
    VL_DEBUG_IF(VL_DBG_MSGF("+    Vtjo___024root___initial__TOP__0\n"); );
    // Init
    std::string __Vtask_broken_str_arg__0__Vfuncout;
    std::string __Vtask_broken_str_arg__1__Vfuncout;
    // Body
    VL_NULL_CHECK(vlSelf->tjo__DOT__unnamedblk1__DOT__tc, "tjo.sv", 6)->__VnoInFunc_broken_str_arg(vlSymsp, 0x666f6fU, __Vtask_broken_str_arg__0__Vfuncout);
    VL_WRITEF("%@\n",-1,&(__Vtask_broken_str_arg__0__Vfuncout));
    VL_NULL_CHECK(vlSelf->tjo__DOT__unnamedblk1__DOT__tc, "tjo.sv", 7)->__VnoInFunc_broken_str_arg(vlSymsp, 
                                                                                std::string("baar"), __Vtask_broken_str_arg__1__Vfuncout);
    VL_WRITEF("%@\n",-1,&(__Vtask_broken_str_arg__1__Vfuncout));
}
```

